const GRADE_COLORS = {
  A: '#5DC987',
  B: '#A3E851',
  C: '#469BC0',
  D: '#888780'
};
function fmtGBP(n) {
  if (n === null || n === undefined || isNaN(n)) return '—';
  return '£' + Number(n).toFixed(2);
}
function render() {
  const summary = appsmith.model.summaryData || {};
  const gradeRows = appsmith.model.gradeData || [];
  const trendData = appsmith.model.trendData || [];
  const selectedModel = appsmith.model.selectedModel;
  const root = document.getElementById('mpRoot');
  if (!selectedModel) {
    root.innerHTML = '<div class="mp-empty">Search for a model above to see pricing history</div>';
    return;
  }
  const estimatedValue = summary.avg_sold_6mo;
  root.innerHTML = `
    <div class="mp-stats-row">
      <div class="mp-card">
        <div class="mp-icon">$</div>
        <div>
          <div class="mp-label">Avg Paid (6mo)</div>
          <div class="mp-value-big">${fmtGBP(summary.avg_paid_6mo)}</div>
        </div>
      </div>
      <div class="mp-card">
        <div class="mp-icon">↗</div>
        <div>
          <div class="mp-label">Avg Sold (6mo)</div>
          <div class="mp-value-big">${fmtGBP(summary.avg_sold_6mo)}</div>
        </div>
      </div>
      <div class="mp-card">
        <div class="mp-icon">⏱</div>
        <div>
          <div class="mp-label">Estimated Value</div>
          <div class="mp-value-big">${fmtGBP(estimatedValue)}</div>
          <div class="mp-sub">based on ${summary.units_sold_6mo || 0} sales, all grades</div>
        </div>
      </div>
    </div>

    <div class="mp-table-card">
      <div class="mp-table-title">Grade Breakdown — Last 6 Months</div>
      <table class="mp-table">
        <thead>
          <tr>
            <th>Grade</th>
            <th>Units Paid</th>
            <th>Avg Paid</th>
            <th>Units Sold</th>
            <th>Avg Sold</th>
          </tr>
        </thead>
        <tbody>
          ${gradeRows.map(r => `
            <tr>
              <td><span class="mp-pill" style="background:${GRADE_COLORS[r.grade] || '#888780'}">${r.grade}</span></td>
              <td>${r.units_paid ?? 0}</td>
              <td>${fmtGBP(r.avg_paid)}</td>
              <td>${r.units_sold ?? 0}</td>
              <td>${fmtGBP(r.avg_sold)}</td>
            </tr>
          `).join('')}
        </tbody>
      </table>
    </div>

    <div class="mp-chart-card">
      <div class="mp-table-title">Sale Price Trend by Grade</div>
      <svg id="mpChartSvg" viewBox="0 0 700 300" style="width:100%; height:auto;"></svg>
      <div class="mp-legend">
        ${Object.keys(GRADE_COLORS).map(g => `
          <div class="mp-legend-item">
            <span class="mp-dot" style="background:${GRADE_COLORS[g]}"></span>
            Grade ${g}
          </div>
        `).join('')}
      </div>
    </div>
  `;
  drawChart(trendData);
}
function drawChart(trendData) {
  const svg = document.getElementById('mpChartSvg');
  if (!svg) return;
  if (!trendData.length) {
    svg.innerHTML = '<text x="350" y="150" text-anchor="middle" fill="#888780" font-size="12">No sale history yet</text>';
    return;
  }
  const months = [...new Set(trendData.map(d => d.month))].sort();
  const grades = ['A', 'B', 'C', 'D'];
  const values = trendData.map(d => Number(d.avg_sold));
  const minV = Math.min(...values) * 0.9;
  const maxV = Math.max(...values) * 1.1;
  const padL = 50,
    padR = 20,
    padT = 10,
    padB = 30;
  const w = 700 - padL - padR;
  const h = 300 - padT - padB;
  const xFor = i => padL + i / Math.max(months.length - 1, 1) * w;
  const yFor = v => padT + h - (v - minV) / (maxV - minV) * h;
  let svgParts = [];
  const steps = 5;
  for (let s = 0; s <= steps; s++) {
    const v = minV + s / steps * (maxV - minV);
    const y = yFor(v);
    svgParts.push(`<line x1="${padL}" y1="${y}" x2="${padL + w}" y2="${y}" stroke="rgba(0,0,0,0.06)" />`);
    svgParts.push(`<text x="${padL - 8}" y="${y + 4}" text-anchor="end" font-size="10" fill="#888780">£${Math.round(v)}</text>`);
  }
  months.forEach((m, i) => {
    const label = new Date(m).toLocaleDateString('en-GB', {
      month: 'short',
      year: '2-digit'
    });
    svgParts.push(`<text x="${xFor(i)}" y="${padT + h + 20}" text-anchor="middle" font-size="10" fill="#888780">${label}</text>`);
  });
  grades.forEach(grade => {
    const points = months.map((m, i) => {
      const row = trendData.find(d => d.grade === grade && d.month === m);
      return row ? {
        x: xFor(i),
        y: yFor(Number(row.avg_sold))
      } : null;
    }).filter(Boolean);
    if (points.length < 1) return;
    const path = points.map((p, i) => (i === 0 ? 'M' : 'L') + p.x + ' ' + p.y).join(' ');
    svgParts.push(`<path d="${path}" fill="none" stroke="${GRADE_COLORS[grade]}" stroke-width="2" />`);
    points.forEach(p => {
      svgParts.push(`<circle cx="${p.x}" cy="${p.y}" r="9" fill="${GRADE_COLORS[grade]}" />`);
      svgParts.push(`<text x="${p.x}" y="${p.y + 3}" text-anchor="middle" font-size="9" font-weight="700" fill="#fff">${grade}</text>`);
    });
  });
  svg.innerHTML = svgParts.join('');
}
let lastModelSnapshot = '';
function checkForUpdates() {
  const currentSnapshot = JSON.stringify(appsmith.model);
  if (currentSnapshot !== lastModelSnapshot) {
    lastModelSnapshot = currentSnapshot;
    render();
  }
}
render();
lastModelSnapshot = JSON.stringify(appsmith.model);
setInterval(checkForUpdates, 300);

